3545 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3546                                                FPClassTest DemandedMask,
3547                                                KnownFPClass &Known,
3548                                                unsigned Depth) {
3549   Use &U = I->getOperandUse(OpNo);
3550   Value *V = U.get();
3551   Type *VTy = V->getType();
3552 
3553   if (DemandedMask == fcNone) {
3554     if (isa<PoisonValue>(V))
3555       return false;
3556     replaceUse(U, PoisonValue::get(VTy));
3557     return true;
3558   }
3559 
3560   // Handle constant
3561   Instruction *VInst = dyn_cast<Instruction>(V);
3562   if (!VInst) {
3563     // Handle constants and arguments
3564     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3565     Known.knownNot(~DemandedMask);
3566 
3567     if (Known.KnownFPClasses == fcNone) {
3568       if (isa<PoisonValue>(V))
3569         return false;
3570       replaceUse(U, PoisonValue::get(VTy));
3571       return true;
3572     }
3573 
3574     // Do not try to replace values which are already constants (unless we are
3575     // folding to poison). Doing so could promote poison elements to non-poison
3576     // constants.
3577     if (isa<Constant>(V))
3578       return false;
3579 
3580     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3581     if (!FoldedToConst || FoldedToConst == V)
3582       return false;
3583 
3584     replaceUse(U, FoldedToConst);
3585     return true;
3586   }
3587 
3588   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3589     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3590     DemandedMask &= ~NoFPClass;
3591   }
3592 
3593   if (Depth == MaxAnalysisRecursionDepth) {
3594     Known.knownNot(~DemandedMask);
3595     return false;
3596   }
3597 
3598   Value *NewVal;
3599 
3600   if (VInst->hasOneUse()) {
3601     // If the instruction has one use, we can directly simplify it.
3602     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3603   } else {
3604     // If there are multiple uses of this instruction, then we can simplify
3605     // VInst to some other value, but not modify the instruction.
3606     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3607                                                 Depth);
